import{_ as a,o as i,c as t,al as n}from"./chunks/framework.BcI6aB5X.js";const c=JSON.parse('{"title":"Kibana","description":"","frontmatter":{"command":"kibana","function":"使用 Kibana","order":2,"options":"login, Dev Tools, Discover"},"headers":[],"relativePath":"databases/elasticsearch/file1/kibana.md","filePath":"databases/elasticsearch/file1/kibana.md","lastUpdated":1777342345000}'),e={name:"databases/elasticsearch/file1/kibana.md"};function l(r,s,h,o,p,k){return i(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="kibana" tabindex="-1">Kibana <a class="header-anchor" href="#kibana" aria-label="Permalink to “Kibana”">​</a></h1><p>Kibana 是 Elastic Stack 的可视化与运维界面，用于查询 Elasticsearch 数据、写 DSL、做仪表盘与索引管理。以下假设你已能访问同一套集群中的 Elasticsearch（参见同章 <a href="./install.html">安装</a>）。</p><h2 id="如何访问" tabindex="-1">如何访问 <a class="header-anchor" href="#如何访问" aria-label="Permalink to “如何访问”">​</a></h2><ul><li><strong>本机或脚本一键环境</strong>：若使用 <code>start-local</code> 等脚本，终端或文档会提示 <strong>Kibana 地址</strong>，常见为 <code>http://localhost:5601</code>（具体端口以实际输出为准）。</li><li><strong>仅自搭 Elasticsearch</strong>：需<strong>单独部署 Kibana 镜像/进程</strong>，并配置与 ES 相同的集群地址与安全认证（见下文 Docker 片段）。</li></ul><p>首次打开若为 <strong>HTTPS</strong> 且为自签证书，浏览器会提示不安全，开发环境可临时继续访问；生产环境应使用可信证书。</p><h2 id="登录" tabindex="-1">登录 <a class="header-anchor" href="#登录" aria-label="Permalink to “登录”">​</a></h2><p>开启 <code>xpack.security</code> 时，使用与 Elasticsearch 内置用户一致的账号，通常为：</p><ul><li>用户名：<code>elastic</code></li><li>密码：与创建集群时设置的 <strong><code>ELASTIC_PASSWORD</code></strong>（或 <code>bootstrap.password</code>）相同。</li></ul><p>若使用其他已创建用户，需具备对应索引与 Kibana 功能的角色权限。</p><h2 id="常用功能速览" tabindex="-1">常用功能速览 <a class="header-anchor" href="#常用功能速览" aria-label="Permalink to “常用功能速览”">​</a></h2><table tabindex="0"><thead><tr><th>入口</th><th>用途</th></tr></thead><tbody><tr><td><strong>Discover（发现）</strong></td><td>按时间轴浏览索引中的文档、过滤字段、保存检索条件。</td></tr><tr><td><strong>Dashboard（仪表盘）</strong></td><td>将可视化图表组合成大屏；可视化多来自 <strong>Lens</strong> 或 <strong>Aggregation</strong>。</td></tr><tr><td><strong>Dev Tools（开发工具）</strong></td><td>打开 <strong>Console</strong>，直接对 ES 发 <code>GET/POST</code> REST 请求，适合调试查询与 mapping。</td></tr><tr><td><strong>Stack Management（堆栈管理）</strong></td><td>创建 <strong>Data view（数据视图）</strong>、管理索引模板、用户与角色、快照等。</td></tr></tbody></table><p>ES 8.x 中，分析数据前通常要在 <strong>Stack Management → Data views</strong> 里新建<strong>数据视图</strong>，绑定到目标索引模式（如 <code>logs-*</code>），之后 Discover、Dashboard 才能选用该视图。</p><h2 id="在-docker-compose-中增加-kibana-可选" tabindex="-1">在 Docker Compose 中增加 Kibana（可选） <a class="header-anchor" href="#在-docker-compose-中增加-kibana-可选" aria-label="Permalink to “在 Docker Compose 中增加 Kibana（可选）”">​</a></h2><p>与 <a href="./install.html">安装</a> 中 Elasticsearch 服务同网段时，可并列增加 Kibana 服务（版本需与 ES <strong>主版本一致</strong>），示例：</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  kibana</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">docker.elastic.co/kibana/kibana:8.15.0</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    container_name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">kibana</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    environment</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ELASTICSEARCH_HOSTS=https://elasticsearch:9200</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ELASTICSEARCH_USERNAME=kibana_system</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ELASTICSEARCH_PASSWORD=\${KIBANA_SYSTEM_PASSWORD}</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    ports</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;127.0.0.1:5601:5601&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    depends_on</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">elasticsearch</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    networks</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">elastic</span></span></code></pre></div><p><strong>说明：</strong> 生产环境应使用 <strong><code>kibana_system</code></strong> 用户及专用密码（首次可用 <code>elasticsearch-reset-password</code> 为 <code>kibana_system</code> 生成密码，再写入环境变量或密钥管理），勿长期使用 <code>elastic</code> 超级用户跑 Kibana；上例为结构示意，实际需与当前 ES 安全、TLS 配置一致。更稳妥的做法是参考官方 <a href="https://www.elastic.co/guide/en/kibana/current/docker.html" target="_blank" rel="noreferrer">Run Kibana on Docker</a> 按版本调整变量。</p><h2 id="dev-tools-示例" tabindex="-1">Dev Tools 示例 <a class="header-anchor" href="#dev-tools-示例" aria-label="Permalink to “Dev Tools 示例”">​</a></h2><p>在 <strong>Dev Tools → Console</strong> 中可试：</p><div class="language-http"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /_cluster/health</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /_cat/indices?v</span></span></code></pre></div><p>若集群启用了 HTTPS 与认证，Kibana 已代你处理与 ES 的连接；在 Console 里写路径即可。</p>`,20)])])}const g=a(e,[["render",l]]);export{c as __pageData,g as default};
